CREATE OR REPLACE VIEW stock14y20_por_talle_vASSELECT articulos.cod_articulo, colores_por_articulo.cod_color_articulo, IFNULL(stock14.cantidad, 0) AS cantidad, rango_talles.posic_1 AS Talle, IFNULL(stock14.cant_1, 0) A cant_1 FROM stock WHERE (cod_almacen = '14') OR (cod_almacen = '20') GROUP BY cod_articulo, cod_cores_por_articulo.cod_color_articulo ON articulos.cod_articulo = colores_por_articulo.cod_articuloUNION ALLSELECT articulos.cod_articulo, colores_por_articulo.cod_color_articulo, IFNULL(stock14.cantidad, 0);;
